Object.assign(documentServiceCopy, documentServiceCopyExtra);

export function getSpecialties(lang) {
  const code = generic[lang] ? lang : 'de';
  const first = baseSpecialties.map((item) => ({
    id: item.id,
    ...item[code],
    ...(code === 'de' && detailParagraphsDe[item.id] ? { paragraphs: detailParagraphsDe[item.id] } : {}),
  }));
  const rest = extraSpecialties.map((item) => ({
    id: item.id,
    label: item.label[code],
    title: item.title[code],
    ...generic[code],
    ...(code === 'de' && detailParagraphsDe[item.id] ? { paragraphs: detailParagraphsDe[item.id] } : {}),
  }));
  return [...first, ...rest];
}

export function getServiceNavigation(lang) {
  const specialties = getSpecialties(lang);
  if (lang === 'de') {
    return [
      ...documentServiceBlocksDe,
      ...specialties.map((item) => ({
        ...item,
        ...(serviceDetailParagraphsDe[item.id] ? { paragraphs: serviceDetailParagraphsDe[item.id] } : {}),
        group: 'specialist',
        kicker: 'Fachübersetzung',
      })),
    ];
  }
  const documentBlocks = documentServiceBlocksDe.map((block) => {
    const copy = documentServiceCopy[lang]?.[block.id] || documentServiceCopy.en[block.id];
    return {
      ...block,
      ...copy,
      ...(serviceTranslatedParagraphs[lang]?.[block.id] ? { paragraphs: serviceTranslatedParagraphs[lang][block.id] } : {}),
      group: block.group,
      id: block.id,
    };
  });
  return [
    ...documentBlocks,
    ...specialties.map((item) => ({
      ...item,
      ...(serviceTranslatedParagraphs[lang]?.[item.id] ? { paragraphs: serviceTranslatedParagraphs[lang][item.id] } : {}),
      group: 'specialist',
      kicker: serviceUi[lang]?.kicker || serviceUi.en.kicker,
    })),
  ];
}

